def gen(rng, size):
    depth = 2 + (max(1, min(size, 1000)) % 7)
    def build(d):
        if d == 0 or rng.random() < 0.25:
            return None
        return {'v': rng.randint(-5, 5), 'l': build(d - 1), 'r': build(d - 1)}
    def mirror(n):
        if n is None:
            return None
        return {'v': n['v'], 'l': mirror(n['r']), 'r': mirror(n['l'])}
    half = build(depth)
    root = {'v': 0, 'l': half, 'r': mirror(half)}
    if rng.random() < 0.5 and root['l'] is not None:
        root['l']['v'] += 1
    # serialize to level-order with nulls
    arr = []
    queue = [root]
    while queue:
        node = queue.pop(0)
        if node is None:
            arr.append(None)
            continue
        arr.append(node['v'])
        queue.append(node['l'])
        queue.append(node['r'])
    while arr and arr[-1] is None:
        arr.pop()
    return [arr]

