class Solution:
    def isSymmetric(self, root):
        def collect(node, side):
            # side-aware traversal: a sentinel marks empties so structure matters
            if node is None:
                return [None]
            if side == 'L':
                return [node.val] + collect(node.left, 'L') + collect(node.right, 'L')
            else:
                return [node.val] + collect(node.right, 'R') + collect(node.left, 'R')
        if root is None:
            return True
        return collect(root.left, 'L') == collect(root.right, 'R')

