class Solution:
    def isSymmetric(self, root):
        def mirror(a, b):
            if a is None and b is None:
                return True
            if a is None or b is None:
                return False
            return a.val == b.val and mirror(a.left, b.right) and mirror(a.right, b.left)
        if root is None:
            return True
        return mirror(root.left, root.right)

